"use client";

import { useState } from "react";
import Link from "next/link";
import Image from "next/image";
import { CheckCircle2, Tag, ArrowLeft, ShieldCheck, RefreshCcw } from "lucide-react";
import { useUser } from "@/context/UserContext";
import { saveAffiliateCode } from "@/services/affiliateService";
import { PLAN_PRICE_USD, PLAN_ORIGINAL_USD, PLAN_DISCOUNT_PCT, PADDLE_PRICE_ID } from "@/lib/config";

const FEATURES = [
  "Unlimited manual trade entries",
  "Daily journal & emotion tracking",
  "Advanced analytics & charts",
  "Up to 3 trading accounts",
  "Set Ups performance analysis",
  "Trading plan & rules tracking",
  "Deposits & withdrawals tracking",
  "Global leaderboard access",
  "Priority support",
];

export default function CheckoutPage() {
  const { user } = useUser();
  const [code, setCode] = useState("");
  const [loading, setLoading] = useState(false);

  const handleSubscribe = async () => {
    setLoading(true);

    // Save affiliate code (fire-and-forget, non-blocking)
    if (user && code.trim()) {
      await saveAffiliateCode(user.id, code);
    }

    // Open Paddle checkout
    if (PADDLE_PRICE_ID) {
      // @ts-expect-error — Paddle JS loaded via script tag
      if (typeof window.Paddle !== "undefined") {
        // @ts-expect-error — Paddle JS loaded via script tag
        window.Paddle.Checkout.open({
          items: [{ priceId: PADDLE_PRICE_ID, quantity: 1 }],
          customer: user?.email ? { email: user.email } : undefined,
          customData: code.trim() ? { affiliate_code: code.trim().toUpperCase() } : undefined,
        });
      } else {
        // Fallback: redirect to Paddle hosted checkout
        window.location.href = `https://buy.paddle.com/product/${PADDLE_PRICE_ID}${user?.email ? `?customer_email=${encodeURIComponent(user.email)}` : ""}`;
      }
    } else {
      // No Paddle configured yet — show a friendly message
      alert("Paddle checkout is not configured yet. Contact support@tradelab.app to subscribe.");
    }

    setLoading(false);
  };

  return (
    <div className="min-h-screen bg-slate-950 flex flex-col">
      {/* Header */}
      <header className="border-b border-slate-800 px-6 py-4 flex items-center gap-4">
        <Link href="/pricing" className="text-slate-500 hover:text-white transition-colors">
          <ArrowLeft className="h-5 w-5" />
        </Link>
        <Link href="/" className="flex items-center gap-2">
          <div className="relative h-7 w-7">
            <Image src="/tradelab-logo-trans.png" alt="TradeLab" fill className="object-contain" />
          </div>
          <span className="text-white font-bold">TradeLab</span>
        </Link>
      </header>

      {/* Content */}
      <div className="flex-1 flex items-start justify-center px-4 py-12">
        <div className="w-full max-w-4xl grid md:grid-cols-2 gap-8 items-start">

          {/* Left: Plan summary */}
          <div className="space-y-6">
            <div>
              <p className="text-xs font-bold uppercase tracking-widest text-blue-400 mb-1">Pro Plan</p>
              <div className="flex items-baseline gap-2">
                <span className="text-slate-500 line-through text-lg">${PLAN_ORIGINAL_USD}</span>
                <span className="text-4xl font-black text-white">${PLAN_PRICE_USD}</span>
                <span className="text-slate-400">/month</span>
                <span className="text-[10px] font-bold px-2 py-0.5 bg-emerald-500/20 border border-emerald-500/40 text-emerald-400 rounded-full">
                  Save {PLAN_DISCOUNT_PCT}%
                </span>
              </div>
              <p className="text-slate-400 text-sm mt-2">Full access. Cancel anytime.</p>
            </div>

            <ul className="space-y-2">
              {FEATURES.map((f) => (
                <li key={f} className="flex items-center gap-2.5 text-sm text-slate-300">
                  <CheckCircle2 className="h-4 w-4 text-blue-400 shrink-0" />
                  {f}
                </li>
              ))}
            </ul>

            {/* Trust badges */}
            <div className="flex flex-col gap-2 pt-2 border-t border-slate-800">
              <div className="flex items-center gap-2 text-xs text-slate-500">
                <ShieldCheck className="h-3.5 w-3.5 text-slate-600" />
                Payments secured by Paddle
              </div>
              <div className="flex items-center gap-2 text-xs text-slate-500">
                <RefreshCcw className="h-3.5 w-3.5 text-slate-600" />
                Cancel anytime — no lock-in
              </div>
            </div>
          </div>

          {/* Right: Checkout form */}
          <div className="rounded-2xl border border-slate-800 bg-slate-900 p-6 space-y-5">
            <h2 className="text-lg font-bold text-white">Complete your subscription</h2>

            {/* Affiliate / referral code */}
            <div className="space-y-1.5">
              <label className="flex items-center gap-1.5 text-xs font-semibold text-slate-400 uppercase tracking-wider">
                <Tag className="h-3.5 w-3.5" />
                Referral Code
                <span className="font-normal normal-case text-slate-600">(optional)</span>
              </label>
              <input
                type="text"
                placeholder="e.g. PARTNER2024"
                value={code}
                onChange={(e) => setCode(e.target.value.toUpperCase())}
                className="w-full bg-slate-800 border border-slate-700 rounded-xl px-4 py-2.5
                  text-white placeholder-slate-600 text-sm font-mono tracking-widest
                  focus:outline-none focus:ring-2 focus:ring-blue-500/50 focus:border-blue-600
                  transition-all"
                maxLength={32}
              />
              <p className="text-[10px] text-slate-600">
                If someone referred you, enter their code. It helps us track and reward them.
              </p>
            </div>

            {/* Order summary */}
            <div className="rounded-xl bg-slate-800/60 border border-slate-700/60 p-4 space-y-2">
              <div className="flex items-center justify-between text-sm">
                <span className="text-slate-400">TradeLab Pro</span>
                <span className="text-slate-300">${PLAN_PRICE_USD}.00/mo</span>
              </div>
              <div className="flex items-center justify-between text-sm">
                <span className="text-slate-500 line-through">Regular price</span>
                <span className="text-slate-600 line-through">${PLAN_ORIGINAL_USD}.00/mo</span>
              </div>
              <div className="border-t border-slate-700/60 pt-2 flex items-center justify-between font-bold">
                <span className="text-white">Total today</span>
                <span className="text-white">${PLAN_PRICE_USD}.00</span>
              </div>
            </div>

            <button
              onClick={handleSubscribe}
              disabled={loading}
              className="w-full py-3 rounded-xl bg-blue-600 hover:bg-blue-500 disabled:opacity-60
                text-white font-bold text-sm transition-all shadow-lg shadow-blue-500/20
                flex items-center justify-center gap-2"
            >
              {loading ? (
                <span className="animate-spin h-4 w-4 border-2 border-white/30 border-t-white rounded-full" />
              ) : (
                <>Subscribe — ${PLAN_PRICE_USD}/month</>
              )}
            </button>

            <p className="text-[10px] text-slate-600 text-center leading-relaxed">
              By subscribing you agree to our{" "}
              <Link href="/terms" className="hover:text-slate-400 underline">Terms</Link>
              {" & "}
              <Link href="/privacy" className="hover:text-slate-400 underline">Privacy Policy</Link>.
              Billed monthly via Paddle. Cancel anytime.
            </p>
          </div>
        </div>
      </div>
    </div>
  );
}

"use client";

import { createContext, useContext, useMemo, ReactNode } from "react";
import { useUser } from "@/context/UserContext";
import { BETA_MODE } from "@/lib/config";

type Plan = "beta" | "pro" | "free";

interface SubscriptionContextType {
  plan: Plan;
  isBeta: boolean;
  isPro: boolean;
  hasAccess: boolean; // true if user can use the app (beta OR pro)
  isLoading: boolean;
}

const SubscriptionContext = createContext<SubscriptionContextType>({
  plan: "beta",
  isBeta: true,
  isPro: false,
  hasAccess: true,
  isLoading: true,
});

export function SubscriptionProvider({ children }: { children: ReactNode }) {
  const { profile, loading } = useUser();

  const value = useMemo<SubscriptionContextType>(() => {
    const planExpired = profile?.plan_expires_at
      ? new Date(profile.plan_expires_at) < new Date()
      : false;
    const plan: Plan = (!profile?.plan || planExpired) ? "free" : (profile.plan as Plan);
    const isBeta = plan === "beta" || BETA_MODE;
    const isPro = plan === "pro";
    const hasAccess = BETA_MODE || isPro || isBeta;
    return { plan, isBeta, isPro, hasAccess, isLoading: loading };
  }, [profile, loading]);

  return (
    <SubscriptionContext.Provider value={value}>
      {children}
    </SubscriptionContext.Provider>
  );
}

export function useSubscription() {
  return useContext(SubscriptionContext);
}

/**
 * Global app configuration constants.
 * BETA_MODE: when true, all authenticated users bypass the subscription gate.
 * Set to false when the beta period ends to enforce payment.
 */
export const BETA_MODE = true;

export const PADDLE_PRICE_ID = process.env.NEXT_PUBLIC_PADDLE_PRICE_ID ?? "";
export const PADDLE_YEARLY_PRICE_ID = process.env.NEXT_PUBLIC_PADDLE_YEARLY_PRICE_ID ?? "";
export const PADDLE_VENDOR_ID = process.env.NEXT_PUBLIC_PADDLE_VENDOR_ID ?? "";

// Monthly plan pricing
export const PLAN_PRICE_USD = 18;
export const PLAN_ORIGINAL_USD = 29;
export const PLAN_DISCOUNT_PCT = Math.round(
  ((PLAN_ORIGINAL_USD - PLAN_PRICE_USD) / PLAN_ORIGINAL_USD) * 100
); // 38

// Yearly plan pricing ($8.25/mo billed as $99/year)
export const PLAN_PRICE_YEARLY_TOTAL = 99;
export const PLAN_PRICE_YEARLY_MONTHLY = Math.round((99 / 12) * 100) / 100; // 8.25
// Savings % vs the monthly price (18 → 8.25 = 54%)
export const PLAN_DISCOUNT_YEARLY_PCT = Math.round(
  ((PLAN_PRICE_USD - PLAN_PRICE_YEARLY_MONTHLY) / PLAN_PRICE_USD) * 100
); // 54

// Free trial
export const TRIAL_DAYS = 7;

